1	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
2	type Step = { op: string; items: Item[] };
3	type Result = { premium: number };
4	type ScenarioInput = { customer: { yearsWithMHPCO: number }; steps: Step[] };
5	type ScenarioOutput = { results: Result[] };
6	
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	};
13	
14	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
15	const CURSED_SURCHARGE_PERCENT = 50;
16	const PROCESSING_FEE = 5;
17	
18	const addSurchargePercent = (amount: number, percent: number): number =>
19	  (amount * (100 + percent)) / 100;
20	
21	const itemPremium = (item: Item): number => {
22	  const base = BASE_PREMIUMS[item.type];
23	  return item.cursed ? addSurchargePercent(base, CURSED_SURCHARGE_PERCENT) : base;
24	};
25	
26	const sumItemPremiums = (items: Item[]): number =>
27	  items.reduce((sum, item) => sum + itemPremium(item), 0);
28	
29	const quotePremium = (items: Item[]): number =>
30	  addSurchargePercent(sumItemPremiums(items), FIRST_INSURANCE_SURCHARGE_PERCENT) + PROCESSING_FEE;
31	
32	export const runScenario = (input: ScenarioInput): ScenarioOutput => ({
33	  results: input.steps.map((step) => ({ premium: quotePremium(step.items) })),
34	});
35

